use std::fs::{create_dir_all, File}; use std::io::{BufWriter, Write};
struct Scenario { name: &'static str, eid: f64, mu: f64, mug: f64, dc: f64, mc: f64 }
fn simulate(s: &Scenario) -> (f64,f64,f64,f64,f64,f64,f64) { let mut output=100.0; let mut ei=0.42; let mut mu=s.mu; let mut ap=1.0; let mut temp=1.2; let mut ce=0.0; let mut cd=0.0; let mut cc=0.0; let mut w=0.0; let mut avg=0.0; let mut n=0.0; let mut fe=0.0; let mut y=2025; while y<=2100 { if y>2025 { output*=1.012_f64.powi(5); ei=(ei*(1.0-s.eid).powi(5)).max(0.02); mu=(mu+s.mug).min(0.98); } let e=output*ei*(1.0-mu); if y>2025 { ap=(ap+0.012*e-0.010*ap).max(0.0); temp=(temp+0.030*ap-0.012*temp).max(0.0); } let d=s.dc*temp.powi(2)*output; let c=s.mc*mu.powi(2)*output; let cons=(output-d-c).max(0.0); let ww=(cons+1.0).ln()/1.015_f64.powi(y-2025); ce+=e; cd+=d; cc+=c; w+=ww; avg+=mu; n+=1.0; fe=e; y+=5; } (fe,temp,ce,cd,cc,w,avg/n) }
fn main() -> std::io::Result<()> { create_dir_all("outputs/tables")?; let file=File::create("outputs/tables/rust_iam_pathway_summary.csv")?; let mut w=BufWriter::new(file); writeln!(w,"scenario,final_emissions,final_temperature_proxy,cumulative_emissions,cumulative_damages,cumulative_mitigation_cost,discounted_welfare_proxy,average_mitigation_rate,diagnostic_label")?; let scenarios=vec![Scenario{name:"delayed_transition",eid:0.006,mu:0.02,mug:0.010,dc:0.012,mc:0.040},Scenario{name:"moderate_transition",eid:0.012,mu:0.06,mug:0.025,dc:0.010,mc:0.040},Scenario{name:"accelerated_decarbonization",eid:0.018,mu:0.10,mug:0.045,dc:0.008,mc:0.055},Scenario{name:"high_innovation_pathway",eid:0.026,mu:0.08,mug:0.040,dc:0.008,mc:0.038}]; for s in &scenarios { let r=simulate(s); let label=if r.1>3.0{"high climate pressure pathway"}else{"lower climate pressure pathway"}; writeln!(w,"{},{:.6},{:.6},{:.6},{:.6},{:.6},{:.6},{:.6},{}",s.name,r.0,r.1,r.2,r.3,r.4,r.5,r.6,label)?; } println!("Rust IAM diagnostics complete."); Ok(()) }
